import React, {useEffect, useState} from "react";
import webproject1 from '../../resources/web-project-1.png';
import webproject2 from '../../resources/web-project-2.png'
// import Modal from "react-modal";
import { Button, Header, Image, Modal } from 'semantic-ui-react'

const WebProjects = ({config}) => {
    const [modalIsOpen,setIsOpen] = useState(false);
    const imgSrc = [webproject1,webproject2]
    function detectMouse(n)
    {
        SetIsShown(n);
    }
    return (
        <div className="ui columns grid"
             onMouseEnter={() => (detectMouse(true))}
             onMouseLeave={() => (detectMouse(false))}
             onClick={()=>(detectMouse(true))}
        >
            <div className="ui ten wide column">
                    <button
                        className={`ui orange inverted button ${config.button}`}
                        onClick={() => setIsOpen(true)}
                        style={{fontSize:"1em",position:"relative"}}>Learn More</button>
                </div>
            <div className="ui large image column" style={{borderRadius:"50%", width:"90vw",zIndex:"0"}}>
                <img src={imgSrc[config.id]}/>
            </div>
            {modalIsOpen && (
                <Modal
                    onClose={() => setIsOpen(false)}
                    onOpen={() => setIsOpen(true)}
                    open={modalIsOpen}
                    trigger={<Button>Show Modal</Button>}
                >
                    <Modal.Header>Select a Photo</Modal.Header>
                    <Modal.Content image>
                        <Image size='medium' src={imgSrc[config.id]} wrapped />
                        <Modal.Description>
                            <Header>{config.projectTitle}</Header>
                            <h4>Technologies: </h4>
                            <p>{config.languageUsed}</p>
                            <h4>Description: </h4>
                            <div className={"description"}>
                                {config.description}
                                {config.descList}
                            </div>
                        </Modal.Description>
                    </Modal.Content>
                    <Modal.Actions>
                        <Button color='black' onClick={() => setIsOpen(false)}>
                            Close
                        </Button>
                        <a className="ui positive right labeled icon button"
                           onClick={() => setIsOpen(false)}
                               href={config.projectURL} target="_blank">Go</a>
                    </Modal.Actions>
                </Modal>
                )

            }
        </div>
    )
};
export default WebProjects;
